// ─────────────────────────────────────────────────────────────────────────────
// LOOKUP FUNCTION
// Returns city data or null if not in database
// Called from app.js after geocoding returns place data
// ─────────────────────────────────────────────────────────────────────────────

// Aliases: maps normalized geocoding keys → CITY_DB keys
// Needed because Open-Meteo returns full city names (e.g. "Frankfurt am Main")
var CITY_ALIASES = {
    "DE-frankfurtammain": "DE-frankfurt",
    "US-newyorkcity": "US-newyork",
    "CH-luzern": "CH-lucerne",
    "TH-krungthepmahanakon": "TH-bangkok",
    "TH-krungthep": "TH-bangkok",
    "GB-cityoflondon": "GB-london",
    "IT-roma": "IT-rome",
    "TR-constantinople": "TR-istanbul",
    "JP-tokyoto": "JP-tokyo",
};

function getCityData(place) {
    if (!place) return null;
    var iso2 = (place.country_code || "").toUpperCase();
    var city = (place.name || "").toLowerCase()
        .normalize("NFD").replace(/[\u0300-\u036f]/g, "")
        .replace(/\s+/g, "");
    var key = iso2 + "-" + city;

    // User-generated cities (localStorage) take priority over static DB
    if (typeof localStorage !== "undefined") {
        var stored = localStorage.getItem("hh_usercity_" + key);
        if (stored) {
            try {
                var userCity = JSON.parse(stored);
                var uCountry = (userCity.country && COUNTRY_DB[userCity.country]) ? COUNTRY_DB[userCity.country] : {};
                return Object.assign({}, uCountry, userCity);
            } catch (_e) { /* ignore parse error */ }
        }
    }

    var cityData = null;

    // Exact match
    if (CITY_DB[key]) cityData = CITY_DB[key];

    // Alias match
    if (!cityData && CITY_ALIASES[key]) cityData = CITY_DB[CITY_ALIASES[key]] || null;

    // Prefix match
    if (!cityData) {
        var keys = Object.keys(CITY_DB);
        for (var i = 0; i < keys.length; i++) {
            var k = keys[i];
            if (k.indexOf(iso2 + "-") !== 0) continue;
            var dbCity = k.slice(iso2.length + 1);
            if (city.indexOf(dbCity) === 0 || dbCity.indexOf(city) === 0) { cityData = CITY_DB[k]; break; }
        }
    }

    // Capital fallback — if city not in DB, use country capital data
    var usingCapitalFallback = false;
    if (!cityData) {
        var capitalKey = COUNTRY_CAPITAL[iso2];
        if (capitalKey && CITY_DB[capitalKey]) {
            cityData = CITY_DB[capitalKey];
            usingCapitalFallback = true;
        }
    }

    if (!cityData) return null;

    // Merge: country layer first, city layer overrides
    var countryData = (cityData.country && COUNTRY_DB[cityData.country]) ? COUNTRY_DB[cityData.country] : {};
    var merged = Object.assign({}, countryData, cityData);
    if (usingCapitalFallback) {
        merged._capitalFallback = true;
        var capName = capitalKey ? capitalKey.slice(iso2.length + 1) : "";
        merged._capitalCityName = capName.charAt(0).toUpperCase() + capName.slice(1);
    }
    return merged;
}

